mapper.select:
SELECT COUNT(*)
FROM CHAT_ROOM
WHERE CHAT_ROOM.PRODUCT_NO = #{productNo}
  AND CHAT_ROOM.BUYER_EMAIL = #{memberEmail}

mapper.update:
UPDATE PRODUCTS
SET VIEW_COUNT = VIEW_COUNT + 1
WHERE PRODUCT_NO = #{productNo}

mapper.select:
SELECT COUNT(*) AS sampleCount, NVL(ROUND(AVG(PRODUCTS.PRODUCT_PRICE)), 0) AS avgPrice, NVL(MAX(PRODUCTS.PRODUCT_PRICE), 0) AS maxPrice, NVL(MIN(PRODUCTS.PRODUCT_PRICE), 0) AS minPrice FROM PRODUCTS WHERE 1 = 1
AND LOWER(PRODUCTS.PRODUCT_NAME) LIKE '%' || LOWER(#{searchWord}) || '%'
AND EXISTS ( SELECT 1 FROM PRODUCT_MEET_LOCATION WHERE PRODUCT_MEET_LOCATION.PRODUCT_NO = PRODUCTS.PRODUCT_NO AND PRODUCT_MEET_LOCATION.FULL_ADDRESS LIKE '%' || #{areaDong} || '%' )
AND PRODUCTS.TRADE_STATUS = '판매중'
AND PRODUCTS.TRADE_METHOD = '택배'
AND PRODUCTS.SALE_TYPE = '나눔' AND NVL(PRODUCTS.PRODUCT_PRICE, 0) = 0
AND PRODUCTS.SALE_TYPE = '판매' AND PRODUCTS.PRODUCT_PRICE IS NOT NULL
AND PRODUCTS.CATEGORY_NO = #{categoryNo}
AND PRODUCTS.PRODUCT_PRICE >= #{priceMin}
AND PRODUCTS.PRODUCT_PRICE <= #{priceMax}

mapper.delete:
DELETE FROM WISHLIST
WHERE MEMBER_EMAIL = #{memberEmail}
  AND PRODUCT_NO = #{productNo}

mapper.select:
SELECT COUNT(*)
FROM WISHLIST
WHERE MEMBER_EMAIL = #{memberEmail}
  AND PRODUCT_NO = #{productNo}

SELECT PRODUCTS.SELLER_EMAIL
FROM PRODUCTS
WHERE PRODUCTS.PRODUCT_NO = #{productNo}

SELECT REPORT_TYPES.TYPE_ID
FROM REPORT_TYPES
WHERE REPORT_TYPES.MAIN_CATEGORY = #{reportMainCategory}
  AND REPORT_TYPES.TYPE_NAME = #{reportSubCategory}

SELECT COUNT(*)
FROM REVIEWS
WHERE TARGET_EMAIL = #{sellerEmail}

SELECT reviewNo, writerEmail, targetEmail, transactionId, rating, oneLineCat, reviewContent, createdAt, writerName, writerProfileImg, productName, productImgUrl, productImgUrls FROM ( SELECT ROW_NUMBER() OVER (
ORDER BY REVIEWS.RATING DESC, REVIEWS.CREATED_AT DESC
ORDER BY REVIEWS.RATING ASC, REVIEWS.CREATED_AT DESC
ORDER BY REVIEWS.CREATED_AT DESC
) AS rno,
REVIEWS.REVIEW_NO AS reviewNo, REVIEWS.WRITER_EMAIL AS writerEmail, REVIEWS.TARGET_EMAIL AS targetEmail, REVIEWS.TRANSACTION_ID AS transactionId, REVIEWS.RATING AS rating, REVIEWS.ONE_LINE_CAT AS oneLineCat, REVIEWS.REVIEW_CONTENT AS reviewContent, REVIEWS.CREATED_AT AS createdAt,
MEMBER.NICKNAME AS writerName, MEMBER.PROFILE_IMG AS writerProfileImg, PRODUCTS.PRODUCT_NAME AS productName,
( SELECT PRODUCT_IMAGE.IMG_URL FROM PRODUCT_IMAGE WHERE PRODUCT_IMAGE.PRODUCT_NO = PRODUCTS.PRODUCT_NO AND PRODUCT_IMAGE.IS_MAIN = 'Y' AND ROWNUM = 1 ) AS productImgUrl,
( SELECT LISTAGG(PRODUCT_IMAGE.IMG_URL, '||') WITHIN GROUP (ORDER BY PRODUCT_IMAGE.SORT_NO) FROM PRODUCT_IMAGE WHERE PRODUCT_IMAGE.PRODUCT_NO = PRODUCTS.PRODUCT_NO ) AS productImgUrls
FROM REVIEWS JOIN MEMBER ON REVIEWS.WRITER_EMAIL = MEMBER.EMAIL JOIN TRANSACTIONS ON REVIEWS.TRANSACTION_ID = TRANSACTIONS.TRANSACTION_ID JOIN PRODUCTS ON TRANSACTIONS.PRODUCT_NO = PRODUCTS.PRODUCT_NO
WHERE REVIEWS.TARGET_EMAIL = ( SELECT PRODUCTS.SELLER_EMAIL FROM PRODUCTS WHERE PRODUCTS.PRODUCT_NO = #{productNo} )
AND REVIEWS.ONE_LINE_CAT = #{reviewCategory}
) WHERE rno BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*)
FROM REVIEWS
WHERE REVIEWS.TARGET_EMAIL =
(
    SELECT PRODUCTS.SELLER_EMAIL
    FROM PRODUCTS
    WHERE PRODUCTS.PRODUCT_NO = #{productNo}
)


    AND REVIEWS.ONE_LINE_CAT = #{reviewCategory}
